3	interface Step {
4	  op: string;
5	  items: Item[];
6	  policy: number;
7	  incident: Incident;
8	}
9	
10	let input = "";
11	process.stdin.setEncoding("utf8");
12	process.stdin.on("data", (chunk) => {
13	  input += chunk;
14	});
15	process.stdin.on("end", () => {
16	  try {
17	    const scenario = JSON.parse(input);
18	    const quotedPolicies: QuoteResult[] = [];
19	    const results = scenario.steps.map((step: Step, index: number) => {
20	      if (step.op === "claim") {
21	        const policy = quotedPolicies[step.policy];
22	        return claim(policy, step.incident);
23	      }
24	      const result = quote(scenario.customer, step.items, { followUp: false });
25	      quotedPolicies[index] = result;
26	      return { premium: result.premium };
27	    });
28	    process.stdout.write(JSON.stringify({ results }));
29	  } catch (error) {
30	    process.stderr.write(error instanceof Error ? error.message : String(error));
31	    process.exit(1);
