95	export interface Damage {
96	  itemType: string;
97	  amount: number;
98	}
99	
100	export interface Incident {
101	  cause: string;
102	  damages: Damage[];
103	}
104	
105	export interface ClaimResult {
106	  payout: number;
107	  remainingCap: number;
108	}
109	
110	const insuranceValueByType: Record<string, number> = {
111	  sword: 1000,
112	  amulet: 600,
113	  staff: 800,
114	  potion: 400,
115	  rune: 250,
116	  moonstone: 250,
117	};
118	
119	const CAP_MULTIPLIER = 2;
120	const DEDUCTIBLE = 100;
121	const HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD = 8;
122	const HALF_REIMBURSEMENT_RATE = 0.5;
123	
124	function totalInsuranceValue(policy: QuoteResult): number {
125	  return policy.items.reduce((sum, item) => sum + insuranceValueByType[item.type], 0);
126	}
127	
128	function remainingCapFor(policy: QuoteResult): number {
129	  return policy.remainingCap ?? CAP_MULTIPLIER * totalInsuranceValue(policy);
130	}
131	
132	function reimbursedAmount(damage: Damage, policy: QuoteResult): number {
133	  const damagedItem = policy.items.find((item) => item.type === damage.itemType);
134	  const halfReimbursementApplies =
135	    damagedItem !== undefined &&
136	    enchantmentLevel(damagedItem) >= HALF_REIMBURSEMENT_ENCHANTMENT_THRESHOLD;
137	  return halfReimbursementApplies
138	    ? damage.amount * HALF_REIMBURSEMENT_RATE
139	    : damage.amount;
140	}
141	
142	function payoutForDamage(damage: Damage, policy: QuoteResult): number {
143	  return reimbursedAmount(damage, policy) - DEDUCTIBLE;
144	}
145	
146	export function claim(policy: QuoteResult, incident: Incident): ClaimResult {
147	  const totalPayout = incident.damages.reduce(
148	    (total, damage) => total + payoutForDamage(damage, policy),
149	    0,
150	  );
151	  const desiredPayout = Math.floor(totalPayout);
152	  const remainingCapBefore = remainingCapFor(policy);
153	  const payout = Math.min(desiredPayout, remainingCapBefore);
154	  const remainingCap = remainingCapBefore - payout;
155	  policy.remainingCap = remainingCap;
156	  return { payout, remainingCap };
157	}
